sub extract_table_info {
    my ($text) = @_;
    my @lines = split /\n/, $text;
    my @tables = ();

    foreach my $line (@lines) {
        # Example condition to match table lines; adjust as needed
        if ($line =~ /Table/) {
            push @tables, $line;
        }
    }

